$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$ff=Join-Path $root 'node_modules\ffmpeg-static\ffmpeg.exe';$dir=Join-Path $root 'video-full';$seg=Join-Path $dir 'segments';New-Item -ItemType Directory -Force $seg|Out-Null
for($i=1;$i-le 20;$i++){$img=Join-Path $dir ('{0:D2}.png'-f$i);$aud=Join-Path $dir ('voice\{0:D2}.mp3'-f$i);$clip=Join-Path $seg ('{0:D2}.mp4'-f$i);&$ff -loglevel error -y -loop 1 -framerate 25 -i $img -i $aud -filter_complex "[0:v]scale=1440:900,zoompan=z='min(zoom+0.00015,1.018)':d=150:s=1440x900:fps=25,format=yuv420p[v];[1:a]apad,atrim=0:6,asetpts=PTS-STARTPTS[a]" -map '[v]' -map '[a]' -t 6 -c:v libx264 -preset medium -crf 20 -c:a aac -b:a 144k $clip;if($LASTEXITCODE-ne 0){throw "Segment $i"}}
$list=Join-Path $seg 'concat.txt';$c=1..20|ForEach-Object{"file '$((Join-Path $seg ('{0:D2}.mp4'-f$_)).Replace('\','/'))'"};[IO.File]::WriteAllLines($list,$c,[Text.UTF8Encoding]::new($false));$out=Join-Path $root 'Waste2Cash_Demo_Complete_FR_2min.mp4';&$ff -loglevel error -y -f concat -safe 0 -i $list -c copy -movflags +faststart $out;if($LASTEXITCODE-ne 0){throw 'Assemblage'};Write-Output $out
